import org.springframework.data.repository.query.Param;
import org.springframework.stereotype.Repository;
import java.util.List;

@Repository
public interface BackupCodeRepository extends JpaRepository<BackupCode, Long> {

    List<BackupCode> findByUserIdAndUsedFalse(Long userId);

    @Query("SELECT bc FROM BackupCode bc WHERE bc.user.id = :userId AND bc.used = false")
    List<BackupCode> findActiveCodesByUserId(@Param("userId") Long userId);

    @Query("SELECT COUNT(bc) FROM BackupCode bc WHERE bc.user.id = :userId AND bc.used = false")
    long countActiveCodesByUserId(@Param("userId") Long userId);

    void deleteByUserId(Long userId);

    List<BackupCode> findByUserId(Long userId);
}

